public class FileUploadHandler
{
    public void HandleFileUpload(string filePath, string fileName, string fileType, int fileSize, string metadata)
    {
        // Connect to database
        using (SqlConnection connection = new SqlConnection("Data Source=.;Initial Catalog=MyDatabase;Integrated Security=True"))
        {
            connection.Open();

            // Insert file metadata into database
            using (SqlCommand command = new SqlCommand("INSERT INTO FileMetadata (FilePath, FileName, FileType, FileSize, Metadata) VALUES (@FilePath, @FileName, @FileType, @FileSize, @Metadata)", connection))
            {
                command.Parameters.AddWithValue("@FilePath", filePath);
                command.Parameters.AddWithValue("@FileName", fileName);
                command.Parameters.AddWithValue("@FileType", fileType);
                command.Parameters.AddWithValue("@FileSize", fileSize);
                command.Parameters.AddWithValue("@Metadata", metadata);

                command.ExecuteNonQuery();
            }

            // Save file to disk
            using (FileStream fileStream = new FileStream(filePath, FileMode.Create))
            {
                using (StreamReader reader = new StreamReader(fileStream))
                {
                    reader.ReadToEnd();
                }
            }
        }
    }
}

