    {
        public static void HandleFileUpload(string filePath, string metadata)
        {
            // Connect to the database
            using (var connection = new SqlConnection("Data Source=<server>;Initial Catalog=<database>;Integrated Security=True"))
            {
                connection.Open();

                // Insert the file metadata into the database
                using (var command = new SqlCommand("INSERT INTO FileMetadata (FilePath, Metadata) VALUES (@FilePath, @Metadata)", connection))
                {
                    command.Parameters.AddWithValue("@FilePath", filePath);
                    command.Parameters.AddWithValue("@Metadata", metadata);
                    command.ExecuteNonQuery();
                }

                // Save the file to disk
                using (var fileStream = new FileStream(filePath, FileMode.Create))
                {
                    using (var stream = new FileStream(filePath, FileMode.Open))
                    {
                        stream.CopyTo(fileStream);
                    }
                }
            }
        }
    }
}

