using System;
using System.IO;
using System.Net;
using System.Web;

public class FileUploadHandler
{
    public void ProcessRequest(HttpContext context)
    {
        // Get the file from the request
        var postedFile = context.Request.Files["file"];

        // Check if the file is valid
        if (postedFile == null || postedFile.ContentLength == 0)
        {
            // File is not valid, return error
            context.Response.StatusCode = (int)HttpStatusCode.BadRequest;
            context.Response.End();
        }

        // Get the file name and extension
        var fileName = Path.GetFileName(postedFile.FileName);
        var fileExtension = Path.GetExtension(fileName);

        // Check if the file is an image
        if (!IsImage(fileExtension))
        {
            // File is not an image, return error
            context.Response.StatusCode = (int)HttpStatusCode.BadRequest;
            context.Response.End();
        }

        // Get the file data
        var fileData = new byte[postedFile.ContentLength];
        postedFile.InputStream.Read(fileData, 0, fileData.Length);

        // Save the file to the server
        var filePath = Path.Combine(Server.MapPath("~/App_Data/uploads"), fileName);
        using (var fs = new FileStream(filePath, FileMode.Create))
        {
            fs.Write(fileData, 0, fileData.Length);
        }

        // Return success
        context.Response.StatusCode = (int)HttpStatusCode.OK;
        context.Response.End();
    }

    private bool IsImage(string fileExtension)
    {
        // Check if the file is an image based on its extension
        return fileExtension.Equals(".jpg", StringComparison.OrdinalIgnoreCase) ||
            fileExtension.Equals(".jpeg", StringComparison.OrdinalIgnoreCase) ||
            fileExtension.Equals(".png", StringComparison.OrdinalIgnoreCase) ||
            fileExtension.Equals(".gif", StringComparison.OrdinalIgnoreCase);
    }
}
